SELECT PO.PO_ID AS poId, S.SUPPLIER_NAME AS "supplierName", RE.EMP_NAME AS "requestEmpName", AE.EMP_NAME AS "approveEmpName", PO.PO_DATE AS "poDate", PO.APPROVE_DATE AS "approveDate", PO.STATUS AS "status", PO.TOTAL_AMOUNT AS "totalAmount", PO.MEMO AS "memo" FROM PURCHASE_ORDER PO JOIN SUPPLIER S ON PO.SUPPLIER_ID = S.SUPPLIER_ID JOIN EMPLOYEE RE ON PO.REQUEST_EMP_ID = RE.EMP_ID LEFT JOIN EMPLOYEE AE ON PO.APPROVE_EMP_ID = AE.EMP_ID
AND PO.STATUS = #{status}
AND PO.SUPPLIER_ID = #{supplierId}
ORDER BY PO.PO_DATE DESC

SELECT * FROM ( SELECT ROW_NUMBER() OVER (ORDER BY PO.PO_DATE DESC) AS "rn", PO.PO_ID AS "poId", S.SUPPLIER_NAME AS "supplierName", RE.EMP_NAME AS "requestEmpName", PO.PO_DATE AS "poDate", PO.STATUS AS "status", PO.TOTAL_AMOUNT AS "totalAmount" FROM PURCHASE_ORDER PO JOIN SUPPLIER S ON PO.SUPPLIER_ID = S.SUPPLIER_ID JOIN EMPLOYEE RE ON PO.REQUEST_EMP_ID = RE.EMP_ID
AND PO.STATUS = #{status}
) WHERE "rn" BETWEEN #{startRow} AND #{endRow}

SELECT COUNT(*)
FROM PURCHASE_ORDER PO


        AND PO.STATUS = #{status}
